long long solve(std::vector<long long> nums, long long k) {
    std::array<long long, 100010> prefix_mod = {0};
    for (size_t i = 0; i < nums.size(); ++i) {
        prefix_mod[i + 1] = (prefix_mod[i] + nums[i]) % k;
    }

    std::array<long long, 100010> mod_count = {0};
    for (long long mod : prefix_mod) {
        mod_count[mod] += 1;
    }

    long long total = 0;
    for (long long i = 0; i < k; ++i) {
