#include <vector>
#include <algorithm>
#include <unordered_map>

long long solve(std::vector<long long> nums, long long k) {
    std::unordered_map<long long, long long> modCount;
    long long prefixMod = 0;
    for (long long num : nums) {
        prefixMod = (prefixMod + num) % k;
        modCount[prefixMod]++;
    }

    long long total = 0;
    for (auto& [mod, count] : modCount) {
        total += (mod * count);
    }

    return total;
}
